import java.sql.*;

public class SecureCode {
    public static void main(String[] args) {
        try {
            // Assume user input obtained from a form or command line argument
            String userInput = "'; DROP TABLE users; --";

            // Connect to the database
            Connection connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            // Create a parameterized SQL statement to prevent SQL injection
            String query = "SELECT * FROM users WHERE username = ?";
            PreparedStatement statement = connection.prepareStatement(query);

            // Set the user input as a parameter in the prepared statement
            statement.setString(1, userInput);

            // Execute the query
            ResultSet resultSet = statement.executeQuery();

            // Process the results (not shown in this snippet)
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

